INSERT INTO `favorites` (`user_id`, `id`, `is_tv`, `title`, `poster_path`, `backdrop_path`, `overview`, `vote_average`, `release_date`, `genre_ids`, `created_at`, `updated_at`, `deleted`) VALUES
(2, 101, 0, 'Leon: Sevginin Gücü', '/5wc5a1z0POdwMfDVrjbeTEhfygV.jpg', '/fj0hwDJEOOHllRim2BMt5L7tbjf.jpg', 'Mathilda, New York’ta yaşayan ailesi dağılmış 12 yaşında küçük bir kızdır. Ailesini sevmeyen Mathilda için en değerli varlığı küçük kardeşidir. Babası uyuşturucu işlerine bulaşınca mafya ailenin tüm bireylerini öldürür. O sırada alışverişte olan Mathilda ise olaydan kılpayı kurtulur ve Leon’un kaldığı daireye saklanır. Leon ise çok soğukkanlı bir katildir. Ancak Mathilda’ya karşı içten bir sevgi besler ve ona kol kanat gerer. Aslında babalık, arkadaşlık gibi kavramlar ona çok yabancıdır.', 8.3, '1994-09-14', '[80,18,28]', 1, 1782816683178, 1),
(2, 194, 0, 'Amelie', '/d6aA2hQmrUN1pGzioXldstNelur.jpg', '/6n53UI4mX9QMfe2S0Pgt8mGebY1.jpg', 'Paris\'te garsonluk yaparak, kendine özgü bir dünyada yaşayan saf, çekingen ve masum bir kızdır Amelie. Annesinin beklenmedik ölümü, babasının soğuk tavırları ve yaşadığı travmalar sonucu, sevimli ve boş şeylerle uğraşarak kendisine eğlence yaratmaya çalışsa da aslında hayatı sıkıcı bulduğu için kendisini son derece yalnız hissetmektedir. Bu kısır döngü Amelie’nin evde bulduğu bir kutuyu ve onun aracılığıyla sahibini keşfetmesiyle birlikte bir anda bıçak gibi kesiliverir... Amelie aşık olmuştur.', 7.9, '2001-04-25', '[35,10749]', 1, 1782816683178, 0),
(2, 1399, 1, 'Game of Thrones', '/1XS1oqL89opfnbLl8WnZY1O1uJx.jpg', '/2OMB0ynKlyIenMJWI2Dy9IWT4c.jpg', 'Krallık dediğin savaşsız olur mu? En güçlü krallığı kurup huzuru sağlamış olsanız bile bu gücü elinizde nasıl tutardınız? Burada yanlış yapana yer yok, affetmek yok. Hanedan entrikaları, kapılı kapılar ardında dönen oyunlar, birilerinin kuyusunu kazmak için düşmanın koynuna girmekten çekinmeyen kadınlar, kardeşler arası çekişmeler, dışlanmalar. Hepsi tek bir amaç için: taht kavgası.', 8.5, '2011-04-17', '[10765,18,10759]', 0, 1782816707634, 0),
(2, 14784, 0, 'Düşüş', '/cQ9W5vWeBiDQP89qmvrqUQPTChT.jpg', '/vNrXoT45xscHY6AN4IGf44vHxVJ.jpg', 'Video klip ve reklamların usta yönetmeni Singh\'in odağında bu kez, sakat bir adam ile küçük bir kızın bir hastanede yaşadıkları olağandışı aşk hikâyesi var. Adam ve kız kendi aralarında, intikam peşindeki beş kahraman hakkında bir masal uydururlar: Maskeli bir kabadayı, Afrikalı kaçak bir köle, Hintli bir mistik, İtalyan bir anarşist ve bir doğabilimci, ıssız bir adaya sürgün edilmişlerdir. Düşüş, akıl almaz sahnelerin rengârenk canlandırma planlarıyla harmanlandığı son dönem filmler arasında, izleyiciyi görselliğiyle yakalayacak, akıllardan kolay silinmeyecek bir yapıt.', 7.625, '2006-09-09', '[12,14,18]', 0, 1782816683178, 0),
(2, 44217, 1, 'Vikingler', '/qkCh6cFSHikSIFTWUQyJ2qJzqsy.jpg', '/13kblIK8DnxMurcRDkeyy2sGR7v.jpg', 'Viking kahramanı Ragnar Lothbrok’un, ileriyi göremeyen, yetersiz bir lidere meydan okuyarak Norse sınırlarını nasıl genişlettiğini seyrettiğimiz gerçekçi bir dram.', 8.095, '2013-03-03', '[10759,18,10768]', 1, 1782816707634, 0),
(2, 46296, 1, 'Spartacus', '/c2GKN4VHCj1dnjFMANRpGkCVBae.jpg', '/zbfXS4o6UykeXsD8djFTyV7Cj4N.jpg', 'Trakyalı bir asker olan Spartacus sürekli baskısı altında kaldıkları Roma Cumhuriyeti ile birlikte Getaelar\'a karşı savaşmak için Roma ordusuna katılır. İlk çarpışmadan sonra Spartacus doğuya doğru çekilen Getae ordusunu takip etmek yerine Karadeniz\'e gitme emri veren Gaius Claudius Glaber\'a karşı gelir ve köyüne gitmeye karar verir. Köyüne yaklaştığında Getaelar\'ın orayı mahvettiğini görür ancak karısı kurtulmuştur. Geceyi bir mağarada karısıyla geçiren Spartacus\'u sabah Roma ordusu bulur. Glaber, Spartacus\'u köle olarak alır ve karısını da Suriyeli bir tüccara satar. Spartacus daha sonra Ludus\'a girer ve karısını bulmak için savaşmaya başlar.', 8.028, '2010-01-22', '[18]', 2, 1782816707634, 0),
(2, 1039764, 0, '生きる', '/gIZUUOsVkJ95CWv3N6uXWnuCRUO.jpg', NULL, '', 0, '2007-09-09', '[10770,18]', 2, 1782816683178, 0);
