INSERT INTO `ratings` (`user_id`, `movie_id`, `is_tv`, `rating`, `genre_ids`, `title`, `poster_path`, `backdrop_path`, `overview`, `vote_average`, `release_date`, `popularity`, `created_at`, `updated_at`, `deleted`) VALUES
(2, 238, 0, 3, '[18,80]', 'Baba', '/vseIVRdN4xasYwStQIi6SI7DcEu.jpg', '/ejdD20cdHNFAYAN2DlqPToXKyzx.jpg', 'Mario Puzo\'nun çok satan kitabından Puzo ve yönetmen Francis Ford Coppola tarafından sinemaya uyarlanan eser, 40\'lar ve 50\'lerin Amerika\'sında, bir İtalyan mafya ailesinin destansı öyküsünü konu alıyor. Corleone ailesi, Don Vito Corleone\'nin başında olduğu, suça dayalı bir örgüt kurmuş olan İtalyan asıllı meşhur bir ailedir. Aile, New York\'taki diğer dört aileyle birlikte New York\'un yeraltı işlerini yönetmektedir. Ancak Corleone ailesini diğerlerinden ayıran özelliği, Don Corleone\'nin cebinde bozuk para gibi taşıdığı politikacılar ve yargıçlardır. Politikacılar ve yargıçlarla olan bu yakın ilişkileri diğer ailelerin açamadığı kapıları açabilmesini sağlamaktadır.', 8.687, '1972-03-14', 40.9483, 1782797064005, 1782797064005, 0),
(2, 278, 0, 3, '[18,80]', 'Esaretin Bedeli', '/7T2SDS5efuJiK45oyKoEzf9RKjw.jpg', '/zfbjgQE1uSd9wiPTX4VzsLi0rGG.jpg', 'Genç ve başarılı bir banker olan Andy Dufresne, karısını ve onun sevgilisini öldürmek suçundan ömür boyu hapse mahkum edilir ve Shawshank hapishanesine gönderilir. İşkence, tecavüz, dayak dahil her türlü kötü koşulun hüküm sürdüğü hapishane koşullarında, Andy\'nin hayata bağlı ve her daim iyi bir şeyler bulma çabası içindeki hali, çevresindeki herkesi çok etkileyecektir. Bir süre sonra parmaklıkların arkasında bile özgür bir yaşam olabileceğine bütün mahkumları inandırır. Bu mahkumlardan biri olan Ellis Boyd \"Red\" ve Andy, unutulmaz bir dostluk kurarak hapishaneyi bambaşka bir yer haline getirirler.', 8.723, '1994-09-23', 110.5352, 1782797052919, 1782797052919, 0),
(2, 549, 1, -1, '[80,18]', 'Law & Order', '/haJ9eHytVO3H3JooMJG1DiWwDNm.jpg', '/tc7canPSAn2X14hYi6Rl3gZm1o4.jpg', 'Law &amp; Order, ABD kaynaklı bir mahkeme ve suç draması konulu bir televizyon dizisi. Dick Wolf tarafından yaratılan dizi 13 Eylül 1990 tarihinde ABD\'nin NBC televizyon kanalında yayına başlamıştır. New York kentinde geçen dizi bir grup savcı ve polis görevlilerinin meslek yaşamlarını konu almaktadır.Dizinin büyük bir başarı kazanması bu diziden türeyen Law &amp; Order: Special Victims Unit, Law &amp; Order: Criminal Intent, Crime &amp; Punishment, Law &amp; Order: Trial by Jury gibi çok sayıda benzer dizilerin yaratılmasına neden olmuştur.Law &amp; Order 2008 yılı itibarıyla ABD televizyonlarında en uzun süre gösterimde kalan dizi durumundadır.', 7.298, '1990-09-13', 197.2882, 1782716849279, 1782716849279, 0),
(2, 764, 1, -1, '[80,18,9648]', 'Midsomer Murders', '/pz7tsWxe0TTdfJnWPjZAEnrSl5M.jpg', '/qVmgq1KXBp6BF2EqYPPaUG9iUGy.jpg', '', 7.489, '1997-03-23', 158.3244, 1782797072812, 1782797072812, 0),
(2, 979, 0, 2, '[18,53,80]', 'Dönüş Yok', '/nsGNiZHpJW2mxd4NlhF8vN5kP0f.jpg', '/xV1EfNSEg6id6juJPr1vM6p9x5X.jpg', '1998 Cannes Film Festivali ödüllü Seul Contre Nous\'un sansasyonel yönetmeni Gaspar Noé\'den, gösterildiği hemen her yerde yoğun tartışmalara ve ağır tepkilere hedef olmuş, aşk, tecavüz ve intikam üzerine sarsıcı bir film. Gösterildiği bazı ülkelerde, seyircilerin bayılmaları ya da koltukları parçalamaları gibi vakalara neden olan film, sansürlenip sansürlenmeyeceği tartışmalarını geride bıraktı ve nihayet huzurlarımızda.', 7.2, '2002-05-22', 34.8485, 1782797068683, 1782797068683, 0),
(2, 1399, 1, 3, '[10765,18,10759]', 'Game of Thrones', '/1XS1oqL89opfnbLl8WnZY1O1uJx.jpg', '/2OMB0ynKlyIenMJWI2Dy9IWT4c.jpg', 'Krallık dediğin savaşsız olur mu? En güçlü krallığı kurup huzuru sağlamış olsanız bile bu gücü elinizde nasıl tutardınız? Burada yanlış yapana yer yok, affetmek yok. Hanedan entrikaları, kapılı kapılar ardında dönen oyunlar, birilerinin kuyusunu kazmak için düşmanın koynuna girmekten çekinmeyen kadınlar, kardeşler arası çekişmeler, dışlanmalar. Hepsi tek bir amaç için: taht kavgası.', 8.463, '2011-04-17', 198.55, 1782716847479, 1782716847479, 0),
(2, 1416, 1, -1, '[18]', 'Grey\'s Anatomy', '/hjJkrLXhWvGHpLeLBDFznpBTY1S.jpg', '/jP0Rhj9OTPDAwQlHQwOLFDdeE8t.jpg', 'Grace Hastanesi\'ne hoş geldiniz! Burada yeni ve acemi doktorlar için en zorlu doktorluk ihtisas devresi programlarından biri uygulanıyor. Bu acımasız eğitimle başa çıkmak zorunda olan kahramanlarımız ise Meredith, Izzie, George, Alex ve Cristina. Onlar dün öğrenciydiler, bugün ise doktor oldular. Eğer yedi yıl boyunca Grace gibi bir cehennemde başarılı olurlarsa cerrahlığa da hak kazanmış olacaklar. Ancak ihtisas devresinin bu kadar zorlu olması, onlar için yaşamlarının geri kalanının durdurduğu anlamına da gelmiyor. Yani bu grup, aynı zamanda kıskanç sevgililer, ebeveynler, tek gecelik ilişkiler ve ev bulma krizleriyle mücadele etmek zorunda. Üstelik kahramanlarımız, bu stresli ve rekabet dolu ortamda dostluklar da kurmaya çalışıyolar.', 8.21, '2005-03-27', 199.143, 1782716845824, 1782716845824, 0),
(2, 1622, 1, -1, '[18,9648,10765]', 'Supernatural', '/8iixmfGx5EIFPdpNvB2JvI3VIqX.jpg', '/ro0tlgnsco4SwbdAgmscLkSlMSL.jpg', 'Evlerinin yandığı şüpheli bir yangında, annelerinin ölümünden sonra, Sam ve Dean Winchester yaşları büyüdükçe babaları ile yollarda bir hayat yaşamaya başlarlar. Yıllar geçer ve bir av sırasında kaybolan babalarını bulmak için kardeşler bir araya gelirler.\n\nAncak, babaları normal bir avcı değildir: o hayaletler, vampirler, ve ruhlar gibi doğaüstü yaratıkları avlar ve aynı şeyi oğullarına da çok küçük yaşlardan itibaren öğretmiştir. Yol boyunca, Sam ve Dean, masum insanları yaratıklar ve hayaletlerden kurtarmak için büyük bir mücadeleye girerler ve babalarının nerede olduğuna dair ipuçlarını toplarlar.', 8.31, '2005-09-13', 177.4176, 1782716859067, 1782716859067, 0),
(2, 2734, 1, -1, '[80,18,9648]', 'Law & Order: Special Victims Unit', '/imaKy0BLfX1iPzj9ZvbOD0D09m6.jpg', '/obtdxPgmfykYwVnvuYXC5f2xKlQ.jpg', 'New York yeraltı dünyasının karanlık yüzünü araştıran bir özel suçlar birimi... New York Polis departmanında cinsel suçlar konusunda uzman dedektiflerden oluşan bu birim, insanın kanını donduran vakaları incelemek zorunda... Her gün yardım isteyen kurbanlar, kapatılmayı bekleyen dosyalarla uğraşan bu ekibin üyeleri, bir yandan da bu araştırmaların özel yaşamlarına olan etkisini dengelemeye çalışıyorlar.', 7.9, '1999-09-20', 303.802, 1782816722872, 1782816722872, 0),
(2, 4057, 1, -1, '[80,18,9648]', 'Criminal Minds', '/hWSb4UnIjlTvnvrP98NbFSO60HA.jpg', '/tUtXfyVy54BY7eJnRtI8Xnmr1ZL.jpg', 'Dizinin temel esprisi, \"bir suçluyu yakalamak istiyorsanız onun gibi düşünün\" sözünde yatıyor. Quantico\'daki Davranış Analizi Ünitesi\'nde çalışan ajanlar, suçluların psikolojilerinden, davranış biçimlerinden yola çıkarak suçu çözüyor. Yöntem: davranış psikolojisinin uygulanması, istatistikler, ajanların deneyimleri, \"hızlı hızlı konuşanlar bir şey saklıyordur\" önermesinde olduğu gibi çıkarımlar.', 8.302, '2005-09-22', 173.4714, 1782729081298, 1782729081298, 0),
(2, 4614, 1, -1, '[80,18,10759]', 'NCIS', '/mBcu8d6x6zB1el3MPNl7cZQEQ31.jpg', '/nn3SuLTO4hum8yAxaY4ql8h6kRk.jpg', 'Deniz Kuvvetleri Kriminal Araştırma Servisi ya da kısa deyişle \"NCIS\". Bu nefes kesen aksiyon drama, deniz kuvvetlerine ilişkin suçları araştıran özel bir ekibin her daim şaşırtıcı serüvenlerine odaklanıyor. Bol dozda mizahla yoğrulmuş \"NCIS\"ın başrolünde \'80\'lerin unutulmaz dizilerinden \"Flamingo Yolu\"yla tanıyıp sevdiğimiz Mark Harmon var.\n\nRenkli kişiliklerden oluşan NCIS ekibinin lideri; eşsiz yeteneklere sahip, eski bir deniz topçu astsubayı olan Özel Ajan Leroy Jethro Gibbs. Gibbs\'in altında çalışan Özel Ajan Anthony Dinozzo ise eski bir cinayet masası dedektifi. Sezgileri çok kuvvetli. Ekibin diğer üyeleri; yetenekli bir bilimadamı olan adli uzman Abby Sciuto ve bilgisayar dahisi NCIS Özel Ajanı Timoth McGee. Ekibin en büyük yardımcısı ise adli tıp doktoru Dr. Donald \"Ducky\" Mallard. Cinayet ve casusluktan, terörizme ve denizaltı hırsızlığına kadar bu özel ajanlar, deniz kuvvetleriyle bağlantılı her türlü suçu araştırmak için dünyayı dolaşıyor.', 7.618, '2003-09-23', 190.9018, 1782716851328, 1782716851328, 0),
(2, 5920, 1, 3, '[80,18,9648]', 'The Mentalist', '/acYXu4KaDj1NIkMgObnhe4C4a0T.jpg', '/q3pCsNvJ7CmdJUz2sJEEUY3pOPC.jpg', 'Patrick Jane isimli bir medyum, sirkte çalışan ve gözlem güçlerini kullanarak insanlar hakkında birtakım fikirler edinip bu fikirleri onlara medyum gibi satan biridir. Bir gün bu özelliği sebebiyle televizyona çıkar ve kendine Red John isimli bir düşman edinir. Red John Jane’in kızını ve eşini öldürünce ortada kalan ve bu ölümlerin sebebinin kendisi olduğunu düşünen Jane, en sonunda FBI’a başvurarak Red John’ın peşine düşmek ister. Her ne kadar ilk başlarda bu isteği geri çevrilse de FBI’ın çözemediği birtakım davaları çözen Jane, bu özel ekibe danışman olarak işe alınır.', 8.357, '2008-09-23', 201.8864, 1782716842589, 1782716842589, 0),
(2, 11012, 0, -1, '[18,10749]', 'Ölesiye', '/alf3JOPP7EYP0iO24gwe5YfRnqo.jpg', '/krhj4Fhb0G3QCmyBtEADxgFFmRX.jpg', 'Bir parlamento üyesi olan Dr. Fleming, oğlunun nişanlısı Anna\'ya tutkulu bir şekilde aşık olur. Tamamen takıntılı bir şekilde, hayatının geri kalanını her şeyden vazgeçmeye razı olarak onunla geçirmek istemektedir. Ancak Anna onun bunu yapmasına izin vermez ve oğluyla evlenmesinin bütün bu olayların örtebileceğini düşünür. Fakat işler düşündükleri kadar kolay ilerlemez. Sonunda ilişkileri ortaya çıkar ve artık bu büyük yıkımla başa çıkmak zorundadırlar.', 6.582, '1992-12-02', 185.0784, 1782816728285, 1782816728285, 0),
(2, 17635, 1, 2, '[10751,18]', 'Aşk-ı Memnu', '/xHulNzEqtgkTuwrRorBRXdGzHML.jpg', '/zcEKO2vdfXAJoAnlgARyhGthLvK.jpg', 'İstanbul\'un sayılı iş adamlarından biri olan Adnan Ziyagil, çok sevdiği eşi İnci öldükten sonra 17 yaşındaki kızı Nihal ve 11 yaşındaki oğlu Bülent ile köşkte bir başına kalır. Çocukların eğitimi için köşke yerleşen Matmazel Deniz de Courton, zaman içerisinde köşkte söz sahibi de olmaya başlar. Matmazel Adnan\'ı yıllarca kendi içinde sevmiş olsa da, Adnan kendisinin yarı yaşında olan Bihter Yöreoğlu’na aşık olur ve onunla evlenir. Önce Bihter bir süre sonra da annesi Firdevs Yöreoğlu köşke yerleşir. Eşini kaybeden Firdevs’in hayattaki tek amacı lüks içindeki yaşamını sürdürebilmektir. Bihter annesine inat uğruna evlendiği Adnan’ı aralarındaki yaş farkına rağmen başlarda sevse de, bir süre sonra Adnan’ın manevi yeğeni hızlı çapkın Behlül Haznedar\'a kapılır. Behlül ise Nihal’in küçüklüğünden beri ona aşık olduğunu anlamamazlıktan gelerek uzatmalı okuduğu üniversitede çapkın yaşamına devam eder; ta ki Bihter’le yasak bir aşkın içine girene kadar...', 6.7, '2008-09-04', 8.4009, 1782681160482, 1782681160482, 0),
(2, 34587, 1, -1, '[10759,18,10768,80]', 'Kurtlar Vadisi', '/yX6JEIijuH6KNCgO8I2yLKu2Psb.jpg', '/sjLv7xpBCP7DZiYS41hMFPRyLQl.jpg', 'Sokaklardan başlayıp belli bir hiyerarşik bütünlük içinde kademe kademe yükselen ve en tepede son derece etkili bir \"konseye\" dönüşerek ülkeyi avcuna almayı amaçlayan çok güçlü bir mafya örgütü ile o örgütle mücadeleye soyunanların serüvenleri anlatılır. Bu hem toplumsal hem de bireysel yansımaları olan bir serüvendir.', 7.3, '2003-01-15', 29.7614, 1782681009624, 1782681009624, 0),
(2, 34899, 1, -1, '[18,10759]', 'Muhteşem Yüzyıl', '/kryRPZTkCxtIc1bGMjIQgblnPe0.jpg', '/gn8k4ztPnrURIIocMOYdWCFknKJ.jpg', 'Osmanlı İmparatorluğu\'nun XV. padişahı I. Süleyman, yirmi altı yaşında bu büyük iktidarı yönetmeye başladığında,  önüne öyle bir hedef koymuştu ki;  Büyük İskender’den daha güçlü ve yaygın bir dünyada egemenlik kuracak ve Osmanlı’yı yenilmez kılacaktı. Bu yürüyüş ona; batıdaki savaş zaferleri nedeniyle Muhteşem Süleyman, doğuda ise adaletli yönetimine atfen Kanunî Sultan Süleyman ismini kazandıracaktı.', 8.1, '2011-01-06', 25.6222, 1782681011455, 1782681011455, 0),
(2, 39176, 1, -1, '[18,10768,10759,80]', 'Behzat Ç.: Bir Ankara Polisiyesi', '/aRqNQ5v2tvZ9ZRAXpYik0JamHkm.jpg', '/pF1OQe4zaXX9vOwxbxjZzws0CAe.jpg', 'Behzat Ç, 1985 yılında Polis Akademisi\'nden mezun olmuş, cinayet bürosunda görev yapmakta olan bir polistir. Hizmet verdiği süre içerisinde almış olduğu cezalar nedeni ile hep başkomiser olarak kalmıştır. Behzat\'ın eski eşi ile yaşadığı problemler kızına karşı ilgisiz kalmasına sebep olur. Bir süre sonra kızı Berna, intihar eder. Behzat, bu olaydan sonra yıkılır. Behzat Ç. ve ekibinde yer alan polisler Harun, Hayalet, Akbaba, Eda, Selim ve Cevdet, sezon boyunca bir yandan Behzat\'ın kızının ölümü ile ilgili olabilecek kişiler ile ilişki kurarken bir yandan da her bir bölümde yaşanan farklı cinayetlerin çözümü ile uğraşırlar.', 7.753, '2010-09-19', 12.2809, 1782681026381, 1782681026381, 0),
(2, 40417, 1, -1, '[10751,35,18,10765]', 'Leyla ile Mecnun', '/3jPLJJXbFabb29mOxZOK0xctcy6.jpg', '/aEQEIXDmjd9otezUu64VFmpO51K.jpg', 'Aynı gün, aynı hastanede dünyaya gelen iki bebek, yatak sayısının azlığından dolayı yan yana yatırılırlar. Ailelerinin \"doğar doğmaz birbirlerini buldular\" sözü üzerine beşik kertmesi yapılan bebekler, isimlerini de efsane aşıklar Leylâ ile Mecnun\'dan alırlar.\n\nAradan 25 yıl geçer. Bir sabah ailesi Mecnun\'a durumu anlatır ve Leyla\'yı istemeye giderler. Mecnun başta bu durumdan rahatsızlık duysa da Leyla\'yı görür görmez aşık olur. Onu etkilemek için ne yapacağını bilemeyen Mecnun, bir gece rüyasında ak sakallı dedeyi görür. Ak sakallı dedenin rüyalarından çıkıp Mecnun ile beraber yaşamaya başlamasıyla da işler karışır.', 8.1, '2011-02-09', 10.0418, 1782681046921, 1782681046921, 0),
(2, 65555, 1, -1, '[18]', 'Kara Sevda', '/wCo8QUccl6hBkCzOrm4AaLgc87J.jpg', '/n0lQ50CfQhB8TfB9hzpeBrJBZ6L.jpg', 'Kara Sevda, 14 Ekim 2015\'te Star TV\'de yayınlanmaya başlayan yeni dizidir. Dizinin başrollerinde Burak Özçivit, Neslihan Atagül ve Kaan Urgancıoğlu yer almaktadır. Yapımcılığını Kerem Çatay\'ın üstlendiği dizinin yönetmen koltuğunda Hilal Saral bulunmaktadır. Senarist kadrosunda Anıl Eke, Özlem Yılmaz ve Burcu Görgün\'ün bulunduğu dizinin oyuncu kadrosunda ayrıca; Kürşat Alnıaçık,Burak Sergen Zeyno Eracar, Orhan Güner, Neşe Baykent, Barış Alpaykut, Melisa Aslı Pamuk yer alıyor. Dizinin çekimleri 1. bölümdeki maden kazası(Zonguldak) hariç İstanbul ilinde gerçekleşmektedir. Dizide madende bir facia yaşandıktan sonra hayatı değişen genç bir maden mühendisinin hikayesi anlatılmaktadır. Genç madenciyi Burak Özçivit canlandırıyor.', 7.841, '2015-10-14', 15.7781, 1782681020179, 1782681020179, 0),
(2, 68398, 1, -1, '[18]', 'Dr. Romantic', '/dmVgWSrtEj39DUv1QEjT6nGpX3L.jpg', '/cmk8d1e1GxrwTaau0Tj4zm1osm0.jpg', 'Üç heyet onaylı, eksantrik ve usta bir cerrah, Seul\'deki prestijli işini bırakır ve genç doktorlara akıl hocalığı yapmak üzere bir taşra hastanesinde işe başlar.', 8.2, '2016-11-07', 29.2418, 1782652706335, 1782652706335, 0),
(2, 68569, 1, -1, '[10751,18]', 'Anne', '/kRYBwumE4hNK4JnHNcU8hRIiDSd.jpg', '/mZD8Y1qlVUY7kwExzdUgZXjiyOK.jpg', '7 yaşındaki Melek, pavyonda çalışan annesi Şule ve onun zalim sevgilisi Cengiz\'le aynı evde yaşamakta ve sistemli olarak dayak ve işkenceye maruz kalmaktadır. Minik kız ne yaşarsa yaşasın minik tavşanı Pamuk\'la ve hayal ettiklerini yazdığı defterle mutlu olmaya çalışmakta ve bir gün hayatının tamamen değişeceğine inanarak hayaller kurmaktan hiç vazgeçmemektedir. Yeterince beslenemediği için çok çelimsiz ve bakımsız görünen minik Melek ile Zeynep arasında çok özel bir bağ kurulur. Zeynep aslında turna kuşlarını fotoğraflayan, soğuk duruşlu, duygularını pek belli etmeyen bir fotoğraf sanatçısıdır. Bir üniversiteye proje sunmuş ve onun onaylanmasını beklerken de geçici olarak okulda ücretli öğretmenlik yapmaya başlamıştır. Kız kardeşleri ve annesi ile 10 yıldır görüşmüyordur. Melek\'in son olarak ölüme terk edilmesi Zeynep\'in bütün gelecek planlarını değiştirmesine neden olur.', 8.092, '2016-10-25', 15.5694, 1782681021511, 1782681021511, 0),
(2, 69459, 1, -1, '[18,10768]', 'Vatanım Sensin', '/n1HhGxf4rFCsaj0pj0UGoowCSWm.jpg', '/tLcPw07fShk90bT5sv3HFxMajMO.jpg', 'Azize üç çocuğu ve kayınvalidesi ile zorlu bir mücadelenin içinde bulur kendini... Canından çok sevdiği kocası Cevdet\'in yokluğuyla ve savaş yıllarının zorluklarıyla mücadele ederek yetiştirir çocuklarını. 1919 yılında, Yıldız (Pınar Deniz) güzeller güzeli, gözü yükseklerde bir genç kız, Hilal ise memleket sevdalısı mücadeleci bir genç kız olmuştur. Ali Kemal ise gönlündeki aşk acısıyla ve kendisine dair öğrendiği hazin sırla yaşamaya çalışan serseri bir mayın gibidir. Azize her birinin dertleriyle uğraşmaya çalışırken, İzmir’in Yunanlılar tarafından işgal edileceği haberi ile sarsılırlar. Oysa bu işgal onlara yıllar önce kaybettikleri birini geri getirecektir. Ama hiç ummadıkları bir şekilde...', 7.9, '2016-11-01', 10.3825, 1782681044591, 1782681044591, 0),
(2, 70798, 1, -1, '[18,10751,35]', 'İstanbullu Gelin', '/alVrRNxDGOlULYdXgnOpPrVP7KL.jpg', '/raosbKSonz7ZkuZsfxHG5LgH0Wl.jpg', 'Annesiz babasız büyümüş, genç yaşta hayatın yükünü sırtlamış, çok güzel ve gururlu bir genç kız olan Süreyya’nın, karizmatik iş adamı Faruk’a aşık olup Bursa’ya gelin gitmesiyle başlayan hikayesi.', 7.4, '2017-03-03', 19.1395, 1782681015177, 1782681015177, 0),
(2, 73586, 1, -1, '[37,18]', 'Yellowstone', '/vOYfRZ0NpUK5hG2CB2dJFnYJlGe.jpg', '/ynSOcgDLZfdLCZfRSYZGiTgYJVo.jpg', 'Dizi, Amerika\'nın Montana eyaletindeki en büyük çiftliği kontrolünde bulunduran, John Dutton\'un liderliğindeki Dutton ailesinin şiddet dolu dünyasını izliyor. Bu büyük arazi, yerliler, şehir planlamacıları ve Amerika\'nın ilk milli parkı olması gibi nedenlerden dolayı sürekli saldırı altında.', 8.268, '2018-06-20', 141.9332, 1782797093415, 1782797093415, 0),
(2, 74823, 1, 3, '[80,10759,18]', 'Çukur', '/7aL9P5NLSgBjdChcwp4cH1OLdKf.jpg', '/xtCzLQOocIajjQ5Mhwp834BQhVX.jpg', 'İstanbul’un en belalı mahallerinden Çukur’un kontrolü Koçova ailesinin elindedir. Koçovalıların Çukur’u yönetirken en önemli kuralları da uyuşturucuya asla izin vermemeleridir. Ancak gözünü bu mahalleye dikmiş ve bu yasağı kırmaya hazırlanan yeni bir grubun ortaya çıkması ile mevcut düzen bozulur.', 7.6, '2017-10-23', 79.3128, 1782680077470, 1782680077470, 0),
(2, 76479, 1, -1, '[10765,10759]', 'The Boys', '/in1R2dDc421JxsoRWaIIAqVI2KE.jpg', '/n6vVs6z8obNbExdD3QHTr4Utu1Z.jpg', 'The Boys, süper kahramanların güçlerini ve şöhretlerini kötüye kullandığı bir evrende geçiyor. Kendilerini kanunu korumaya adayan ve “The Boys” olarak adlandırılan bir grup insan, yozlaşmış süper kahramanları ortadan kaldırmak için zorlu bir yolculuğa çıkar.', 8.45, '2019-07-25', 218.8613, 1782680059474, 1782680059474, 0),
(2, 77532, 1, 3, '[18]', 'Kadın', '/nGW4STJLVazkq41RcFa7kGe12qI.jpg', '/87jtXEQrDGgRTbbYiDvqYWcOFWp.jpg', 'Kocası Sarp’ın ölümünden sonra Bahar’ı hayata bağlayan iki şey vardır: Çocukları Nisan (7) ve Doruk (4). Onlarla elele verip hayatı bir oyuna, fakirliği eğlenceye, yokluğu neşeye çevirmeyi başarır. İnsanın yüzü güldüğünde kalbinin de onunla birlikte gülümseyeceğine inanır.', 7.588, '2017-10-24', 6.9721, 1782681642655, 1782681642655, 0),
(2, 79026, 1, -1, '[10759,10765]', 'Hakan: Muhafız', '/mj6z8wMzcYPt9pwJqHxy0Avlnum.jpg', '/scrqQwSarTbq80oUdZrj7cbpscv.jpg', 'Günümüz İstanbulu\'nda yaşayan ve kadim bir gizli birlikle olan bağını keşfeden genç bir adam, şehri ölümsüz bir düşmandan kurtarmak için maceraya atılır.', 7.2, '2018-12-14', 6.5107, 1782681100754, 1782681100754, 0),
(2, 79744, 1, -1, '[80,18,35]', 'The Rookie', '/70kTz0OmjjZe7zHvIDrq2iKW7PJ.jpg', '/6iNWfGVCEfASDdlNb05TP5nG0ll.jpg', 'Küçük bir kasabada yaşayan kırk yaşındaki John Nolan’ın en büyük hayali polis memuru olmaktır. Yaşadığı ölümcül kazanın ardından hayallerinin peşinden koşan John, yaşadığı kasabayı terk ederek Los Angeles’a gider. Los Angeles Polis Departmanı’nda göreve başlayan John, çalıştığı birimde orta yaş krizi de dahil birçok farklı sorunla boğuşmak zorunda kalır.', 8.552, '2018-10-16', 240.9744, 1782816733732, 1782816733732, 0),
(2, 80411, 1, -1, '[18,35,10766]', 'Erkenci Kuş', '/rGjYq9bi5jpAMZTJnou1UNpmKWj.jpg', '/uJ3HalVLkaOeH1lvDdrEmeqFxds.jpg', 'Sanem sabahları birkaç saat babasının bakkalında çalıştıktan sonra bütün gününü hayal kurarak ve kitabı üzerinde çalışarak geçirmektedir ve hayatından son derece mutludur. Ta ki anne babası kendisine doğru düzgün bir iş bulmazsa evlenmek zorunda olduğunu söyleyene kadar! Sanem bunun üzerine mecburen ablasının iş yerinde çalışmaya başlar. Hayallerini süsleyen büyük aşkının kendisini orada beklediğinden habersizdir henüz, üstelik bilmeden Can\'a ve şirkete kurulan bir tuzağın parçası olur... Yalanlar üzerine kurulan bir aşk olabilir mi? Ya Sanem? Nefret ettiği Can\'a kalbini kaptırabilir mi?', 8.1, '2018-06-26', 16.3963, 1782681018206, 1782681018206, 0),
(2, 82328, 1, -1, '[10751,18]', 'Bir Zamanlar Çukurova', '/ayRjBKyBXzKGHajgVGsiMiK5THy.jpg', '/8vXYq2l38DsPzGD8lpokinZiPuV.jpg', 'Dizide aşkı için öldürmeyi göze almış Yılmaz ile sevgilisi yaşasın diye kendini istemediği bir adamla yaptığı evliliğe hapseden Züleyha\'nın hikayesi anlatılıyor. Ama bu hikayede sadece ayrı düşen iki sevgili yok! Ailesinin görkemli geçmişini ve biricik oğlunu korumak için kanatlarını açmış bir Hünkâr\'ın savaşı da var; aşık olduğu kadını tutsak etmeyi göze alan Demir de! Ve elbette sınırsız aşkların coğrafyasında, geçmişten bugüne uzanan hesaplaşmalar, paylaşılamayan topraklar da! Aşkın sınırsız, kavganın ölümüne, umudun inadına yaşandığı Çukurova\'da ihtiras ve zorbalık sınavlarından geçen bir aşkın hikayesi.', 7.741, '2018-09-13', 11.6168, 1782681030458, 1782681030458, 0),
(2, 82452, 1, 2, '[10759,10765,18,10751]', 'Avatar: The Last Airbender', '/lzZpWEaqzP0qVA5nkCc5ASbNcSy.jpg', '/xUB3xFMgsHgPmdWnUWkHTJ03vHa.jpg', 'Avatar olarak bilinen bir çocuk, savaş hâlindeki dünyayı kurtarmak için dört element gücünde de ustalaşmalı ve onu durdurmaya kararlı olan acımasız bir düşmanla savaşmalıdır.', 7.813, '2024-02-22', 268.102, 1782816726194, 1782816726194, 0),
(2, 83533, 0, 3, '[878,12,14]', 'Avatar: Ateş ve Kül', '/8kknNk7PbOcDUXynUZYZ7EHnKAA.jpg', '/u8DU5fkLoM5tTRukzPC31oGPxaQ.jpg', 'Pandora gezegeninde geçen destansı macera devam ediyor. Sully ailesi, Pandora\'nın Kül halkı kabilesiyle tanışır ve yeni tehditlerle yüzleşirler. İnsanlar, Pandora\'nın kaynaklarını sömürmeye devam ederken, Na\'vi halkı doğayla uyum içinde yaşamaya çalışır. Jake ve Neytiri, ailelerini korumak ve Pandora\'yı savunmak için büyük bir mücadeleye girişirler.', 7.6, '2025-12-17', 146.1621, 1782816736490, 1782816736490, 0),
(2, 87623, 1, -1, '[18]', 'Hercai', '/xDHKKIQrwL3vP3BKov5TeBTzvRD.jpg', '/pcZUSUH31odGlq41XktxLVmjNSm.jpg', 'Midyat\'ın en güçlü ailelerinden Şadoğullarının torunlarından biri olan Reyyan ile yıllar önce öldürülen anne babasının intikamını almak isteyen Miran\'ın imkansız aşk hikayesi.', 7.754, '2019-03-15', 11.662, 1782681027978, 1782681027978, 0),
(2, 92967, 1, -1, '[18]', 'Mucize Doktor', '/ZNxfeXYnlUGYk1cMzL7CBvUnHs.jpg', '/j9orEeA4twmIEQtHdaAW0L1L7nE.jpg', 'Savant sendromlu deha Ali Vefa’nın en büyük hayali doktor olmaktır. Engeline ve karşılaştığı bütün önyargılara rağmen tıp fakültesini bitirmiş, stajını tamamlamış ve geriye sadece ihtisas yapmak kalmıştır. Yaşadığı taşra şehrinden ayrılır ve manevi babası Adil Erinç’in Başhekimi olduğu İstanbul Berhayat Hastanesi’nde Cerrahi Bölüm Asistanı olarak işe başlamak üzere yola çıkar. Ama havaalanında meydana gelen bir kaza Ali’yi hayatının en önemli toplantısına geç bırakır. Aynı sıralarda hastane yönetim kurulu toplanmış, Ali’nin işe alınıp alınmayacağını tartışmaktadır. Adil hariç kimse otizmli birinin doktor olabileceğine inanmaz. Ve Ali, saatlerce geç kalarak, korka korka, kendisine acımayla, inançsızlıkla bakan yönetim kurulunun karşısına çıkar… Önyargılar kırılabilir mi? Hayaller gerçek olabilir mi?', 8.068, '2019-09-12', 13.341, 1782681024433, 1782681024433, 0),
(2, 93405, 1, 1, '[10759,9648,18]', 'Squid Game', '/yACIAqAkSLkX4coHafpyLWAtQjw.jpg', '/2meX1nMdScFOoV4370rqHWKmXhY.jpg', 'Para sıkıntısı çeken yüzlerce oyuncu, çocuk oyunlarında yarışmaları için aldıkları tuhaf daveti kabul eder. İçeride onları cazip bir ödül ve ölüm riski beklemektedir.', 7.856, '2021-09-17', 61.4403, 1782652672250, 1782652672250, 0),
(2, 94997, 1, 2, '[10765,18,10759]', 'House of the Dragon', '/6YM292PX2gSIBk16hufmlGT3iQW.jpg', '/h37hqVLmCW00ImewLAHT1DadOky.jpg', 'George R.R. Martin\'in \"Fire & Blood\" adlı eserinden uyarlanan ve Game of Thrones\'taki olaylardan 200 yıl öncesini konu alan dizi, Targaryen Hanesi\'nin gücünün zirvesinde olduğu dönemde bir iç veraset savaşını anlatıyor.', 8.352, '2022-08-21', 592.0857, 1782816715890, 1782816715890, 0),
(2, 95603, 1, -1, '[10768,10759,18]', 'Kuruluş: Osman', '/rQUhcrcvWoPHjxRc6hzlD2enmRK.jpg', '/puLaqdcTRwFxwv9S3PO6jA3ep7J.jpg', 'Dizi, Ertuğrul Gazi\'nin oğlu ve Osmanlı İmparatorluğu\'nun kurucusu Osman Bey\'in hayatına odaklanacak.', 7.917, '2019-11-20', 61.5612, 1782681000458, 1782681000458, 0),
(2, 96348, 1, -1, '[9648,18,10765]', 'Atiye', '/23hcx6YvPrmEgQWAA0ZFyXL9jh3.jpg', '/tOvVG4uigMTTZiZdUeNMd1BA22U.jpg', 'Atiye, genç ve güzel bir ressamdır. Ailesi ve sevgilisi Ozan’la mutlu bir hayatı olan Atiye, dünyanın en eski tapınaklarından olan Göbeklitepe’ye bir ziyaret gerçekleştirir. Atiye’nin bölgede yaptığı gezi sırdasında, Erhan adındaki bir arkeolog, Atiye ile Göbeklitepe arasında mistik bir bağlantı olduğuna dair bir sembol keşfeder. Bu olayın peşini bırakmayan ve irdelemeye başlayan Atiye, geçmişin izlerini de bulmaya çalışır ve kendisine bambaşka bir yol çizer. Atiye, geçmişi kovaladıkça ve yeni detaylara ulaştıkça, geçmişle geleceği, gerçek ile ruhani olayları birbirinden ayırt edememeye başlar.', 7.344, '2019-12-27', 4.4173, 1782681141774, 1782681141774, 0),
(2, 96648, 1, -1, '[10765,10759]', 'Sweet Home', '/kJEcSBMPacDJuAihPNmcUEgon1Y.jpg', '/mceCXNTny6a5F3rQgShLoyARw4l.jpg', 'İnsanlar acımasız canavarlara dönüşerek dehşet saçarken sorunlu bir genç ile komşuları hayatta kalmak ve insanlıklarına tutunmak için savaşır.', 8.229, '2020-12-18', 96.3251, 1782652659811, 1782652659811, 0),
(2, 99966, 1, -1, '[10759,18,10765]', 'All of Us Are Dead', '/d9yefq8dNke4UbuqStBtUcO9TxD.jpg', '/8hp2CuGnw1iP5dLBVMAPUv23swx.jpg', 'Okudukları lisede bir zombi virüsü salgınının patlak vermesiyle kapana kısılan öğrenciler ya bir çıkış yolu bulacak ya da korkunç bir şekilde enfekte olacak.', 8.277, '2022-01-28', 32.8983, 1782652695890, 1782652695890, 0),
(2, 100868, 1, -1, '[18,10751,10766]', 'Emanet', '/wmyqaUTyfEuOBi6uy0Wvw9i3dVH.jpg', '/dOpHCDo2bCQIrrnuofKkZExMo3G.jpg', 'Zengin ve karizmatik bir iş adamı olan Yaman Kırımlı ile masum ve mütevazı bir hayatı olan Seher Kerimoğlu\'nun hikâyesini içeren dizide hem Yaman hem de Seher ailesini kaybeden ve kendilerinden başka bir yakını olmayan yeğenleri Yusuf\'u emanet olarak görmektedir. Yaman Kırımlı çok zengin bir adamdır ama geçmişte yaşadığı zor günlerin etkisinden bir türlü kurtulamaz. İki ağabeyi olan Yaman, onları terk ederek başka bir adamla giden annesini hiç affetmez. Annesinin evi terk etmesiyle intihar eden babasını ise bir türlü unutamaz. Yaman Kırımlı bu durumdan sonra kadınlardan nefret eder ve hiçbir kadına güvenmemektedir. Yaman yeğeni Yusuf\'u da acımasız ve güçlü biri olarak yetiştirmek ister Seher ise emanet olarak gördüğü yeğenini almak ve onu kendi istediği gibi yetiştirmek ister. Tabi Yaman Kırımlı buna asla izin vermeyecektir. Seher ise Yaman\'ın tüm zorluklarına rağmen yeğenini almak ister ve bu konu da her şeyi göze alacaktır.', 7.651, '2020-09-07', 22.4652, 1782681013462, 1782681013462, 0),
(2, 100897, 1, -1, '[35,18]', 'Aşk 101', '/l6pLzAgUU2QpJ6KlsReqSqwWnfa.jpg', '/uxxr14xvFgpGDdTAoLJJFsAZYSB.jpg', 'Öğretmenlerinin bir basketbol koçuna âşık olmasını sağlamaya çalışan dört isyankâr ve bir örnek öğrenci, birlikte arkadaşlığı, aşkı ve kendileri olma cesaretini öğrenir.', 7.749, '2020-04-24', 4.3829, 1782681143722, 1782681143722, 0),
(2, 104877, 1, -1, '[18,35]', 'Sen Çal Kapımı', '/nzBenFJ2D2MCWTwTt2uc4BGWLtA.jpg', '/9qq8LpOoBLYq8MxiMugn0gf9qJd.jpg', 'Sen Çal Kapımı dizisinde, hayatta bütün umutlarını eğitimine bağlayan Eda Yıldız, yurt dışı eğitim bursunu keserek lise mezunu kalmasına neden olan Serkan Bolat ile karşı karşıya gelir. Serkan Bolat, Eda’ya kendisiyle iki ay nişanlı taklidi yaparsa, bursunu geri vermeyi teklif eder. Eda nefret ettiği bu adamın teklifini önce reddetse de koşullar değişince kabul etmek zorunda kalır. Nişanlı taklidi yaparken, Serkan ve Eda, bütün doğru bildiklerini unutturacak, tutkulu, zorlu bir ilişki yaşamaya başlayacaktır.', 8.223, '2020-07-08', 30.9707, 1782681007601, 1782681007601, 0),
(2, 110562, 1, -1, '[18]', 'Sadakatsiz', '/47tPvMrNzquyC9GTrELfX9vRQNm.jpg', '/76aveobsWhFYon5DHP7CAjo9GYJ.jpg', 'Asya, başarılı bir doktordur. Kocası Volkan, harika bir eş ve oğulları Ali’ye şahane bir babadır. Üç kişilik çekirdek aile, hep huzur ve mutluluk dolu bir hayat yaşamışlardır... Beyaz güller kadar saf bir ilişkidir Asya’nın gözünde yıllardır süren evlilikleri... Ta ki; Asya, Volkan’ın atkısındaki sarı uzun saç telini görene dek…', 8.068, '2020-10-07', 15.1584, 1782681022901, 1782681022901, 0),
(2, 112888, 1, -1, '[35,18]', 'Gerçek Güzellik', '/gaCOvKGG2qEnsijNHEAigYcQ1U3.jpg', '/3E1GroTJCRdIYHa5n62GqjmqxQR.jpg', 'Lim Ju-Kyung, lise öğrencisidir. Küçüklükten beri dış görünüşünü beğenmemektedir. Doğal güzelliğini saklamak için her zaman makyaj yapmaktadır. Mükemmel makyaj becerileri onu değiştirerek doğal güzelliğinin başkaları tarafından görünmesini önler.', 8.263, '2020-12-09', 28.7989, 1782652709729, 1782652709729, 0),
(2, 113268, 1, -1, '[18,9648,10759]', 'The Uncanny Counter', '/xwXgYXqxLRAYfVGUaS1STEFnmzZ.jpg', '/jNyK0FF7t7oaU4wMpRkEnEIOVlW.jpg', 'Gündüzleri erişte dükkânında çalışıp geceleri iblis peşinde koşan Avcılar, insanlarla beslenen hain iblisleri yakalamak için özel güçlerini kullanır.', 8.328, '2020-11-28', 29.2122, 1782652708039, 1782652708039, 0),
(2, 119769, 1, -1, '[10759,80,18]', 'Taxi Driver', '/qDLhCBbl7eUSesMSV9rYqHR8qwW.jpg', '/i1SyUHsi45psSH1xy9sM0in8FKJ.jpg', 'Konusu: Kim Do Ki(Lee Je Hoon), Deniz Harp Okulu’ndan mezunu olan eski bir özel kuvvetler subayıdır. Annesi bir seri katil tarafından öldürüldükten sonra hayatı değişir. Kim Do Ki artık lüks bir taksi şoförüdür ve Rainbow Taxi Company için çalışıyordur. Bu şirket sadece sıradan bir taksi şirketi değildir. Şirket özel bir ‘intikam çağrı’ hizmeti sunmaktadır. Müşterileri intikam almalarını isterlerse ‘Rainbow Taxi’ çalışanları müşterilerinin bu isteklerini yerine getirmektedir.\n\nTürü: Dram, Aksiyon, Hukuk', 8.139, '2021-04-09', 33.1871, 1782652693237, 1782652693237, 0),
(2, 124364, 1, -1, '[9648,18,10765]', 'FROM', '/pRtJagIxpfODzzb0T0NAvZSzErC.jpg', '/m7eiSGHFzr584zFmetGqkqaU6BN.jpg', 'Amerika Birleşik Devletleri\'nin ortasındaki kabus gibi bir şehir, içine giren herkesi tuzağa düşürür. Kasaba sakinleri, normallik duygusunu sürdürmek ve bir çıkış yolu aramak için savaşırken, güneş battığında ortaya çıkan korkunç yaratıklar da dahil olmak üzere, çevredeki ormandan gelen tehditlere karşı da hayatta kalmak için çabalar.', 8.509, '2022-02-20', 872.1045, 1782816711562, 1782816711562, 0),
(2, 127529, 1, -1, '[18,10759,80]', 'Bloodhounds', '/j4BjkbSqY7Cbc4XcdKMyJGyr9iT.jpg', '/zhsEnDNCQX5dlI2wbKzV90pV0B9.jpg', 'Zor durumdakilere borç veren hayırsever bir iş insanı adına çalışan iki boksör, mali açıdan çıkmazda olanların sırtından geçinen acımasız bir tefeciyi devirmek için el ele verir.', 8.494, '2023-06-09', 63.0753, 1782652666304, 1782652666304, 0),
(2, 135157, 1, -1, '[18,10765,10759,9648]', 'Alchemy of Souls', '/pGs6UA4rPUZEokDyTwAGdRvwrAD.jpg', '/nBZyWSGAUEzCH7Mna0zUNTpBQlQ.jpg', 'Yaşamını kör bir kadının bedeninde sürdüren bir büyücü, kaderini değiştirmek için ondan yardım isteyen, prestijli bir aileye mensup bir adamla karşılaşır.', 8.575, '2022-06-18', 34.9221, 1782652684639, 1782652684639, 0),
(2, 157336, 0, 2, '[12,18,878]', 'Yıldızlararası', '/xbiycuc84TrieEWwkkuH2hoEa9S.jpg', '/2ssWTSVklAEc98frZUQhgtGHx7s.jpg', 'Dünya\'nın giderek yaşanmaz hale gelmesiyle başlayan tarım krizi ve doğal felaketler, insanları yok olma tehlikesiyle karşı karşıya bırakmıştır. Teknik bilgisi ve becerisi yüksek olan Cooper, geniş mısır tarlalarında çiftçilik yaparak geçinmektedir; amacı iki çocuğuna güvenli bir hayat sunmaktır. Onlarla yaşayan büyük baba Donald çocuklara göz kulak olurken, henüz 10 yaşındaki kızı Murph şaşırtıcı bir zekaya sahiptir. Geçmişte bıraktığı bilim insanı kariyerini özleyen Cooper\'un karşısına bir gün beklenmedik bir teklif çıkar ve ailesinin, dahası insanlığın güvenliği için zorlu bir karar alması gerekir...', 8.479, '2014-11-05', 66.8713, 1782797087896, 1782797087896, 0),
(2, 200709, 1, -1, '[10759,18]', 'Weak Hero', '/jXd83QZhBDAFno4OGqHcMMDs56i.jpg', '/q5mJ4oKfGc6Cr9reIHFzD0pQzre.jpg', 'Yetenekli ancak içe dönük bir öğrenci, beklenmedik arkadaşlarının yardımıyla zorbalara ve amansız düşmanlara kafa tutar. Ama nasıl bir tehlikeye bulaştığından habersizdir.', 8.711, '2022-11-18', 78.8955, 1782652662829, 1782652662829, 0),
(2, 202010, 1, -1, '[18]', 'Kuş Uçuşu', '/7PPVzg636s6Q15PYdr7HhkNQg9o.jpg', '/opHnAwvV1XY2EgR7gScAv2cdjMg.jpg', 'Bakış açıları, yaklaşımlar ve hedefe giden yolda yürüme biçimleri X kuşağına göre artık bambaşkadır. Genç bir kadın olan Aslı da kariyer basamaklarını tırmanmak için çok çalışmaya güvenmek yerine \'kuş uçuşu\' gitmeye çalışır. Yeni dünyanın yöntemleriyle en üste ulaşmaya çalışan Aslı amacına ulaşabilecek midir?', 7, '2022-06-03', 4.2964, 1782681145837, 1782681145837, 0),
(2, 206180, 1, -1, '[18]', 'Zeytin Ağacı', '/p2UqCeIEdDqq0MTR8HwGEfZfu6J.jpg', '/eND0QkFMyqWONmAy1lBKtPjsrFF.jpg', 'Ada, Sevgi ve Leyla\'nın “rakı, balık, Ayvalık” olarak başlayan macerası, onları geçmişleriyle barıştırırken kendi yaşamları için yepyeni kararlar almalarını sağlar.', 7.8, '2022-07-28', 35.5058, 1782681006045, 1782681006045, 0),
(2, 210865, 1, -1, '[10751,18]', 'Yalı Çapkını', '/pzDHrbX7780TcNrV4P7j5xrgE6u.jpg', '/vDqCoaMU5FUAuUs0EvL4OAUCxJk.jpg', 'Yalı Çapkını, Gaziantepli Korhan Ailesi\'nin direği Halis Ağa\'nın (Çetin Tekindor) el bebek gül bebek yetiştirilmiş torunu Ferit\'in (Mert Ramazan Demir) evlenmesine karar vermesiyle gelişecek olayları konu alıyor.', 8.295, '2022-09-23', 51.9672, 1782681002706, 1782681002706, 0),
(2, 214078, 1, -1, '[18,10765,9648,10759]', 'Şahmaran', '/1fKsga4dTxTRNFp1ktUWUa7P1Ib.jpg', '/bkdZHK0Nh1YaRXkk2j8vUGYQd6i.jpg', 'Şahsu, öğretim görevlisi olarak gittiği Adana’da yıllar önce annesini terk eden büyükbabasıyla yüzleşmeye kararlıdır. Bu yolculukta kendisini Şahmaran’ın soyundan gelen ve Mar adı verilen sıradışı ve gizemli bir topluluğun ortasında bulur. Aşkın ve bilgeliğin en büyük sembollerinden olan Şahmaran efsanesine inanan Mar ırkı, Şahsu’nun da gelmesiyle tarihi kehanetin tamamlanmasını beklemektedir. Büyükbabasından geçmişin hesabını sormak üzere yola çıkan Şahsu’nun Maran ile yollarının kesişmesiyle bir daha hiçbir şey eskisi gibi olmayacaktır…', 6.71, '2023-01-20', 5.3402, 1782681137113, 1782681137113, 0),
(2, 214079, 1, -1, '[18,9648]', 'Terzi', '/i8YLOXlSJoBfG2cvaZQyu58Z9Fg.jpg', '/5vaDrDaJij9JFF7cwrJvAMypxLY.jpg', 'Ünlü terzi Peyami, en iyi dostunun müstakbel eşi için gelinlik dikmektedir. Ama hiç görmediği bu kız beklenmedik şekilde hayatına girince, Peyami’nin sırlarına bir yenisi eklenir.', 7.34, '2023-05-02', 4.9332, 1782681139643, 1782681139643, 0),
(2, 219246, 1, -1, '[18]', 'When Life Gives You Tangerines', '/koMkV9qm0PEZHDmX5dRpBpMH1FY.jpg', '/5yk3QwnQxzwKfhU1tlDkV2PSIBz.jpg', 'Jeju Adası\'nda neşeli bir kız ve kararlı bir erkeğin hikâyesi, inişler ve çıkışlarla dolu, ömür boyu sürecek bir öyküye dönüşerek aşkın zamana meydan okuyabileceğini kanıtlar.', 8.8, '2025-03-07', 28.3845, 1782652712173, 1782652712173, 0),
(2, 231503, 1, -1, '[18]', 'Yabani', '/lQ5k6i7Bv3ssV4uotxZpTdKCgC9.jpg', '/897uYgM4gtY0MdPRszIJngRJrIp.jpg', 'Köklü bir aileden kaçırılıp sokaklara düşen bir çocuğun, yıllar sonra evine dönmesi ile kendini yeniden var etme mücadelesini anlatıyor.', 8.654, '2023-09-12', 35.51, 1782681004172, 1782681004172, 0),
(2, 259837, 1, -1, '[10759,35,10765,18]', 'The WONDERfools', '/uARtDxJDtISHnM2BxaSKvlQpWrc.jpg', '/810mXC0xkxXVtoKIPGGVgO9PuLh.jpg', 'Yüzyıl dönümünde geçen bu çılgın aksiyon komedide, bir grup şapşal kasabalı aniden süper güçlere sahip olur ve kıyamet paniği artarken giderek güçlenen bir kötülüğe karşı savaşır.', 9.071, '2026-05-15', 35.5215, 1782652674470, 1782652674470, 0),
(2, 273240, 1, -1, '[18]', 'Off Campus', '/cbODFqkcmRgrYH8NkG4Q4Hcg8Z1.jpg', '/52sp0vPhLOWrZ1QoZIWiapronM.jpg', 'Hannah Wells, hokey kaptanı Garrett Graham\'a, hoşlandığı kızı kazanması için ders verir. Anlaşmaları, geçmişleriyle yüzleştikçe yakınlaşmaya dönüşür. Logan, Dean, Tucker ve Allie adlı arkadaşlar, üniversite hayatı ve aşkı keşfederler.', 8.979, '2026-05-13', 284.1439, 1782816719268, 1782816719268, 0),
(2, 276161, 1, -1, '[10759,18,35]', 'Teach You a Lesson', '/36BnxmIvWvOsMmlQfbI0ilTfuvh.jpg', '/vyG93jhmPL7tBIhRtCLa5mdBKob.jpg', 'Okullarda otoriteye saygı yerle bir olduğunda işleri yoluna koymak için gelen sıra dışı müfettişler, ders kitaplarında bulunmayan katı ve ciddi dersler vermeye başlar.', 9.478, '2026-06-05', 157.7108, 1782652647367, 1782652647367, 0),
